    ('cat_feelings_faces_books', 1, 1, 'visible', true, false, 'Best for friendship wobbles', 'On Sudden Hill', 'Linda Sarah', 'Amazon UK', 'https://amzn.to/3ekaAPm', NULL, '£7.99', 'in_stock', '5-7', 'A heartwarming story about two best friends whose relationship is tested when a new boy wants to join their cardboard box adventures.', 'Perfect for nearly-threes navigating the tricky waters of three-way friendships and feeling left out. It gently shows that friendships can change and grow.', 'Directly addresses the stage shift of friend play becoming more complex and the feelings of jealousy that can arise.', 'The characters are slightly older, but the themes resonate well with older toddlers.', 'buy', true, 'A thoughtful gift that feels useful without becoming a lecture.', 'Choose warm, specific stories rather than abstract emotion labels.', NULL, 'strong', ARRAY['https://www.booksfortopics.com/book/on-sudden-hill/']::text[], 'none'),
    ('cat_feelings_faces_books', 2, 2, 'visible', true, true, 'Best for managing worries', 'What If, Pig?', 'Linzie Hunter', 'Amazon UK', 'https://amzn.to/3CqO2Yb', NULL, '£6.99', 'in_stock', '2-5', 'A sweet and funny story about Pig, a tremendous worrier, and his friend Mouse who helps him turn anxiety into optimism.', 'Great for this age as imagination grows and ''what ifs'' start. It models how friends can support each other through worries.', 'Fits the 34-36m stage where children start noticing feelings more and can use words to express anxieties.', 'None', 'buy', true, 'A thoughtful gift that feels useful without becoming a lecture.', 'Choose warm, specific stories rather than abstract emotion labels.', NULL, 'strong', ARRAY['https://www.booksfortopics.com/book/what-if-pig/']::text[], 'none'),
    ('cat_feelings_faces_books', 3, 3, 'visible', true, true, 'Best for everyday emotions', 'Find Your Happy', 'Emily Coxhead', 'Amazon UK', 'https://amzn.to/3MJJinr', NULL, '£7.99', 'in_stock', '2-5', 'A joyful and imaginative book of feelings featuring Sloth, offering practical ideas for when you feel sad, angry, or shy.', 'A bright, welcoming book that gives honest advice and easy ways to cheer yourself up, perfect for discussing everyday feelings.', 'Helps children notice and manage feelings, fitting the cluster objective.', 'None', 'buy', true, 'A thoughtful gift that feels useful without becoming a lecture.', 'Choose warm, specific stories rather than abstract emotion labels.', NULL, 'strong', ARRAY['https://www.booksfortopics.com/book/find-your-happy/']::text[], 'none'),
    ('cat_feelings_faces_books', 4, 4, 'visible', true, true, 'Best for holding grudges', 'The Sour Grape', 'Jory John', 'Amazon UK', 'https://amzn.to/3kL2rtW', NULL, '£8.99', 'in_stock', '2-5', 'A witty story about a grape who holds grudges until he learns that forgiveness and compassion can turn a sour grape sweet.', 'Brilliant for exploring fairness and forgiveness in friendships, which are key concepts as friend play gets more complex.', 'Addresses the messy side of friend play and the importance of forgiveness.', 'Uses some puns that might go over a toddler''s head, but the core message lands.', 'buy', true, 'A thoughtful gift that feels useful without becoming a lecture.', 'Choose warm, specific stories rather than abstract emotion labels.', NULL, 'strong', ARRAY['https://www.booksfortopics.com/book/the-sour-grape/']::text[], 'none'),
    ('cat_feelings_faces_books', 5, 5, 'visible', true, true, 'Best for understanding boundaries', 'Sometimes I''m a Baby Bear, Sometimes I''m a Snail', 'Moira Butterfield', 'Amazon UK', 'https://amzn.to/3P1z1z1', NULL, '£6.99', 'in_stock', '2-5', 'Uses charming animal comparisons to help children express feelings of shyness, social anxiety, and physical boundaries.', 'Excellent for helping nearly-threes articulate when they want to play and when they need space, crucial for turn-taking and friend play.', 'Provides words for complex social feelings, fitting the stage shift perfectly.', 'None', 'buy', true, 'A thoughtful gift that feels useful without becoming a lecture.', 'Choose warm, specific stories rather than abstract emotion labels.', NULL, 'strong', ARRAY['https://www.booksfortopics.com/book/sometimes-im-a-baby-bear-sometimes-im-a-snail/']::text[], 'none'),
