DO $$
DECLARE
  v_visible_count INTEGER;
  v_backup_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_visible_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '34-36m'
    AND ct.slug IN ('cat_balance_stepping_stones', 'cat_feelings_faces_books', 'cat_threading_beads', 'cat_visual_routine_cards')
    AND s.status = 'visible'
    AND s.is_visible = true;

  IF v_visible_count <> 40 THEN
    RAISE EXCEPTION 'Expected 40 visible Stage 3 picks for 34-36m, got %', v_visible_count;
  END IF;

  SELECT COUNT(*) INTO v_backup_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '34-36m'
    AND ct.slug IN ('cat_balance_stepping_stones', 'cat_feelings_faces_books', 'cat_threading_beads', 'cat_visual_routine_cards')
    AND s.status = 'backup'
    AND s.is_visible = false;

  IF v_backup_count <> 20 THEN
    RAISE EXCEPTION 'Expected 20 backup Stage 3 picks for 34-36m, got %', v_backup_count;
  END IF;
END $$;

COMMIT;
